import { useRef, useState, useEffect } from 'react';
import {
  Badge,
  Button,
  message,
  Popconfirm,
  Space,
  Typography,
  Card,
  Row,
  Col,
  Statistic,
  Descriptions,
  Spin,
} from 'antd';
import {
  PlusOutlined,
  ReloadOutlined,
  CloudServerOutlined,
  DatabaseOutlined,
  ClockCircleOutlined,
} from '@ant-design/icons';
import { ActionType, ProColumns, ProTable } from '@ant-design/pro-components';
import { ModalForm, ProForm, ProFormDigit, ProFormSwitch, ProFormText, ProFormTextArea } from '@ant-design/pro-components';
import {
  getSystemConfigs,
  createSystemConfig,
  updateSystemConfig,
  deleteSystemConfig,
  batchDeleteSystemConfigs,
  getServerInfo,
  getMinioConfig,
  saveMinioConfig,
  getDatabaseConfig,
  type SystemConfig,
  type CreateSystemConfigDto,
  type UpdateSystemConfigDto,
  type ServerInfo,
  type MinioConfig,
  type DatabaseInfo,
} from '@/services/system';

const { Text } = Typography;

function formatBytes(bytes: number): string {
  if (bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

function formatUptime(seconds: number): string {
  const d = Math.floor(seconds / 86400);
  const h = Math.floor((seconds % 86400) / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const parts: string[] = [];
  if (d > 0) parts.push(`${d}d`);
  if (h > 0) parts.push(`${h}h`);
  if (m > 0) parts.push(`${m}m`);
  return parts.join(' ') || '< 1m';
}

export default function SystemPage() {
  const actionRef = useRef<ActionType>(undefined);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingConfig, setEditingConfig] = useState<SystemConfig | null>(null);
  const [selectedRowKeys, setSelectedRowKeys] = useState<string[]>([]);
  const [serverInfo, setServerInfo] = useState<ServerInfo | null>(null);
  const [infoLoading, setInfoLoading] = useState(false);
  const [minioConfig, setMinioConfig] = useState<MinioConfig | null>(null);
  const [dbInfo, setDbInfo] = useState<DatabaseInfo | null>(null);
  const [minioSaving, setMinioSaving] = useState(false);

  const fetchServerInfo = async () => {
    setInfoLoading(true);
    try {
      const info = await getServerInfo();
      setServerInfo(info);
    } catch (err: any) {
      message.error(err.message || 'Failed to fetch server info');
    } finally {
      setInfoLoading(false);
    }
  };

  const fetchMinioConfig = async () => {
    try {
      const data = await getMinioConfig();
      setMinioConfig(data);
    } catch { /* ignore */ }
  };

  const fetchDbInfo = async () => {
    try {
      const data = await getDatabaseConfig();
      setDbInfo(data);
    } catch { /* ignore */ }
  };

  useEffect(() => {
    fetchServerInfo();
    fetchMinioConfig();
    fetchDbInfo();
  }, []);

  const columns: ProColumns<SystemConfig>[] = [
    {
      title: 'Key',
      dataIndex: 'key',
      width: 220,
      copyable: true,
    },
    {
      title: 'Value',
      dataIndex: 'value',
      ellipsis: true,
      width: 280,
      render: (_, record) => (
        <Text ellipsis={{ tooltip: record.value }} style={{ maxWidth: 240 }}>
          {record.value}
        </Text>
      ),
    },
    {
      title: 'Description',
      dataIndex: 'desc',
      ellipsis: true,
      search: false,
      render: (_, record) =>
        record.desc ? (
          <Text ellipsis={{ tooltip: record.desc }} style={{ maxWidth: 200 }}>
            {record.desc}
          </Text>
        ) : (
          <Text type="secondary">--</Text>
        ),
    },
    {
      title: 'Updated',
      dataIndex: 'updatedAt',
      valueType: 'dateTime',
      width: 180,
      search: false,
    },
    {
      title: 'Action',
      key: 'action',
      width: 140,
      search: false,
      render: (_, record) => (
        <Space>
          <Button
            type="link"
            size="small"
            onClick={() => {
              setEditingConfig(record);
              setModalOpen(true);
            }}
          >
            Edit
          </Button>
          <Popconfirm
            title="Confirm delete?"
            description="This action cannot be undone."
            onConfirm={async () => {
              try {
                await deleteSystemConfig(record.id);
                message.success('Deleted');
                actionRef.current?.reload();
              } catch (err: any) {
                message.error(err.message || 'Delete failed');
              }
            }}
            okText="Confirm"
            cancelText="Cancel"
          >
            <Button type="link" size="small" danger>
              Delete
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  const handleSubmit = async (values: Record<string, any>) => {
    try {
      if (editingConfig) {
        const dto: UpdateSystemConfigDto = {
          key: values.key,
          value: values.value,
          desc: values.desc || '',
        };
        await updateSystemConfig(editingConfig.id, dto);
        message.success('Updated');
      } else {
        const dto: CreateSystemConfigDto = {
          key: values.key,
          value: values.value,
          desc: values.desc || '',
        };
        await createSystemConfig(dto);
        message.success('Created');
      }
      setModalOpen(false);
      setEditingConfig(null);
      actionRef.current?.reload();
      return true;
    } catch (err: any) {
      message.error(err.message || 'Operation failed');
      return false;
    }
  };

  const handleBatchDelete = async () => {
    try {
      const result = await batchDeleteSystemConfigs(selectedRowKeys);
      message.success(`Deleted ${result.count} config(s)`);
      setSelectedRowKeys([]);
      actionRef.current?.reload();
    } catch (err: any) {
      message.error(err.message || 'Batch delete failed');
    }
  };

  const handleSaveMinio = async (values: any) => {
    setMinioSaving(true);
    try {
      const saved = await saveMinioConfig({
        endpoint: values.endpoint,
        port: Number(values.port),
        accessKey: values.accessKey,
        secretKey: values.secretKey,
        bucket: values.bucket,
        useSSL: !!values.useSSL,
      });
      setMinioConfig(saved);
      message.success('MinIO 配置已保存');
    } catch (err: any) {
      message.error(err.message || '保存失败');
    } finally {
      setMinioSaving(false);
    }
  };

  const memUsagePercent = serverInfo
