} from 'antd';
import {
  PlusOutlined,
  DeleteOutlined,
  EyeOutlined,
  CodeOutlined,
  CheckCircleOutlined,
  LoadingOutlined,
  CloseCircleOutlined,
  ClockCircleOutlined,
  RocketOutlined,
  ExclamationCircleOutlined,
  SaveOutlined,
  AppstoreOutlined,
} from '@ant-design/icons';
import {
  previewGenerate,
  executeGenerate,
  getGenerateStatus,
  getTables,
  getLatestVersion,
  startModuleUpdate,
  getUpdateStatus,
  listAllPackages,
  getPackageConfig,
  saveFromConfig,
  type AutoCodeDto,
  type AutoCodeField,
  type GenerateJobStatus,
  type GenerateStep,
  type PackageListItem,
} from '@/services/autocode';
import { useUserStore } from '@/stores/user';
import { getDictionaries, type Dictionary } from '@/services/dictionary';

const { Text, Title } = Typography;

const FIELD_TYPE_OPTIONS = [
  { value: 'varchar', label: 'String (varchar)' },
  { value: 'text', label: 'Long Text (text)' },
  { value: 'integer', label: 'Integer (integer)' },
  { value: 'bigint', label: 'Big Integer (bigint)' },
  { value: 'decimal', label: 'Decimal (numeric)' },
  { value: 'boolean', label: 'Boolean (boolean)' },
