        pagination={{ pageSize: 20 }}
        toolBarRender={() => [
          <Button
            key="set"
            type="primary"
            icon={<PlusOutlined />}
            onClick={() => {
              setEditingRecord(null);
              setModalOpen(true);
            }}
          >
            Configure Buttons
          </Button>,
        ]}
      />

      <ModalForm
        title="Configure Button Permissions"
        open={modalOpen}
        onOpenChange={(open) => {
