            key="batch-delete"
            title="Confirm batch delete?"
            description={`Selected ${selectedRowKeys.length} logs`}
            onConfirm={handleBatchDelete}
            okText="Confirm"
            cancelText="Cancel"
          >
            <Button danger>
              Batch Delete ({selectedRowKeys.length})
            </Button>
          </Popconfirm>
        ),
      ]}
    />
  );
}

