                      }}
                      columns={[
        {
          title: '明细名称',
          dataIndex: 'name',
          valueType: 'text',
          formItemProps: { rules: [{ required: false }] },
        },
        {
          title: '数量',
          dataIndex: 'number',
          valueType: 'text',
          formItemProps: { rules: [{ required: false }] },
        },
        {
          title: '单价',
          dataIndex: 'price',
          valueType: 'text',
          formItemProps: { rules: [{ required: false }] },
        },
                        { title: '操作', valueType: 'option', width: 60 },
                      ]}
                    />
                    <Button
                      type="dashed"
                      block
                      icon={<PlusOutlined />}
                      style={{ marginTop: 8 }}
                      onClick={() => {
                        const tempId = Date.now().toString() + '_' + Math.random().toString(36).slice(2, 8);
                        const newRow = { id: tempId, name: '', number: '', price: '' };
