import {
  ModalForm,
  ProFormText,
  ProFormTextArea,
  ProFormDigit,
  ProFormSwitch,
} from '@ant-design/pro-components';
import {
  getTestList,
  createTest,
  updateTest,
  deleteTest,
  batchDeleteTest,
  type Test,
  type CreateTestDto,
  type UpdateTestDto,
} from '@/services/test';
import { getMyBtnPerms } from '@/services/authority-btn';

export default function TestPage() {
  const actionRef = useRef<ActionType>(undefined);
