            setTimeout(() => setEditingRecord(null), 300);
          }
        }}
        onFinish={handleSubmit}
        modalProps={{ destroyOnClose: true }}
      >
          <ProFormText
            name="name"
            label="名称"
            placeholder="名称"


          />

          <ProFormText
            name="description"
            label="描述"
            placeholder="描述"


          />
      </ModalForm>
    </>
  );
}
